import React from "react";
import "./style.css";

function goToHome() {
            window.parent.location.href = "/";
        }
        function goToSugar() {
            window.parent.location.href = "/sugarMonitor";
        }
        function goToInput() {
            window.parent.location.href = "/emotionMonitor";
        }
        function goToReport() {
            window.parent.location.href = "/report";
        }
        function goToExercise() {
            window.parent.location.href = "/exerciseMonitor";
        }
function Dashboard(){
    return (
        <>
            <div className="backgroundImage">
                <h1>Welcome to Dashboard</h1>
                <div style="display: flex;">
                    <div class="cardcontainer" onclick="goToSugar()"><p> Add Sugar Levels</p></div>
                    <div  class="cardcontainer" onclick="goToInput()"><p>Track Today's Food and Emotion</p></div>

                </div>
                <div style="display: flex;">
                    <div class="cardcontainer" onclick="goToReport()"><p>View weekly Report</p></div>
                    <div class="cardcontainer" onclick="goToExercise()"><p>Add Today's Physical Activity</p></div>
                </div>
            </div>
        </>
    );
}

export default Dashboard;
